mapper.select:
SELECT hospital_id, hospital_name, address, latitude, longitude, contact_info, hospital_type, emergency_department, created_time, updated_time, del_flag, 6371000 * ACOS( COS(RADIANS(#{userLat})) * COS(RADIANS(latitude)) * COS(RADIANS(longitude) - RADIANS(#{userLng})) + SIN(RADIANS(#{userLat})) * SIN(RADIANS(latitude)) ) AS distance FROM hospital_info WHERE del_flag = 0 AND 6371000 * ACOS( COS(RADIANS(#{userLat})) * COS(RADIANS(latitude)) * COS(RADIANS(longitude) - RADIANS(#{userLng})) + SIN(RADIANS(#{userLat})) * SIN(RADIANS(latitude)) ) <= #{radius}
AND ( hospital_name LIKE CONCAT('%', #{keyword}, '%') OR address LIKE CONCAT('%', #{keyword}, '%') OR hospital_type LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY distance ASC LIMIT #{maxResults}
